var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"나 참, 이런 버려진 공장에 무슨 볼일이 있다고 우리한테 정찰을 보내?","JPN":"まったく。何の用があってこんな捨てられた工場を偵察させるの？","ENG":"Geez, what could she possibly want from this abandoned factory by sending us here on patrol?","TWN":"有沒有搞錯！這種破爛工廠會有什麼事？有必要派我們來巡邏嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"부사장님은 네가 이쪽 지리를 잘 안다고 생각했겠지. 고향이랑 가까운 곳이라며?","JPN":"副社長はお前がこっちの地理に詳しいと思ったんだろう。地元から近いんだって？","ENG":"The Vice President probably thought you were familiar with this area. It's close to where you come from, right?","TWN":"副總可能以為你很熟悉這裡的地理環境吧？你的故鄉不是離這裡很近嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"넌 지구가 고향이니까 대서양 밑바닥에 뭐가 있는지도 잘 알고 있겠네?","JPN":"あんたは地球が故郷だから大西洋の海底に何があるのかもちろん知ってるのよね？","ENG":"You're from Planet Earth. Does that mean you know what lives at the bottom of the Atlantic Ocean?","TWN":"要這麼說的話，那你的故鄉是地球，你應該也很清楚大西洋海底有些什麼吧？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"어… 모래상어?","JPN":"えっと……サメか？","ENG":"Err... Sand sharks?","TWN":"應該有…大鳳梨吧？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"…말을 말자.","JPN":"はあ……聞いた私が馬鹿だったわ。","ENG":"...Deliver me!","TWN":"…當我沒問。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"내가 알고 있는 거라곤, 이곳이 내가 태어나기 전부터 이런 폐허였다는 것뿐이야.","JPN":"私が知ってるのは、私が生まれる前からここは廃墟だったってことだけ。","ENG":"What I know is that this place was ruined long before I was born.","TWN":"我對這個地方唯一的認識，就是在我出生前，這裡就已經跟廢墟一樣！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"농장 밖에 없는 시골 분위기엔 어울리지 않는 공장터지.","JPN":"農場しかないド田舎の風景には似合わない工場ね。","ENG":"A factory site in the countryside that looks out of place.","TWN":"四周圍明明都是農地，卻有一個突兀的廢工廠。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"직접 부지 안에 들어와본 건 이번이 처음이라고.","JPN":"敷地内に入ったのは今回が初めてなの。","ENG":"This is my first time actually setting foot in it.","TWN":"而且我也是第一次進到裡面來好嗎！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"이쪽도 다 살펴본 것 같은데? 침식파 검출도 안 되고, 평범한 잡동사니들 밖에 없어.","JPN":"こっちも全部調べたんだが……侵食波も検出されないし、普通のがらくたしかねえな。","ENG":"We've checked everywhere on this side. No Corruption rays. There's only ordinary-looking junk here.","TWN":"這邊好像也檢查過了吧？沒有檢測到侵蝕波，只有一堆雜物而已。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"이 냉장고라도 가져갈까? 아직 쓸만해보이는데.","JPN":"この冷蔵庫でも持って帰ろうか？　まだ使えそうに見えるぞ。","ENG":"What about we take this refrigerator with us? It looks usable.","TWN":"這個冰箱要帶走嗎？好像還能用欸？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"관심 없어. 그나저나 빨리 이 냄새나는 곳에서 철수하자.","JPN":"興味ないわ。さっさとこんな臭い所から撤退するわよ。","ENG":"Not interested. Come on, let's get out of this stinky place.","TWN":"沒興趣！還是趕快離開這個臭氣熏天的地方吧！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"…제시카.","JPN":"……ジェシカ。","ENG":"...Jessica.","TWN":"…潔西卡。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"아, 오르카. 너도 폐기물 더미 그만 뒤지고 비누로 손부터…","JPN":"あ、オルカ。あんたも廃棄物の山を探るのはもうやめて、石鹸で手を洗っ……","ENG":"Ah, Orca. Stop rummaging through the waste and wash your hands—","TWN":"喂，奧爾卡！你也不要再翻那堆垃圾了，趕快把手…"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"응? 그건 뭐야? TV?","JPN":"ん？　それはなに？　テレビ？","ENG":"Hm? What's that? A TV?","TWN":"嗯？那是什麼？電視嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"오, 낡은 모델이긴 해도 상태는 제법 괜찮은데?","JPN":"おお、古いモデルではあるが状態は悪くないんじゃないか？","ENG":"Oooh, it's an old model, but looks pretty good.","TWN":"哇！雖然是舊的款式，但好像還能看欸？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"이거… 계속 말을 걸고 있어.","JPN":"これが……ずっと話しかけてくるの。","ENG":"It keeps talking to me.","TWN":"它…一直在對我說話。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"응? TV가 말을 건다고?","JPN":"え？　テレビが話しかけてくる？","ENG":"Huh? The TV is talking to you?","TWN":"啥？電視跟你說話？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"네 안에 있는 오르카가 속삭이는 것처럼 말이야?","JPN":"あんたの中のオルカが囁くみたいに？","ENG":"You mean, like Orca, inside you?","TWN":"就像你裡面的奧爾卡在講悄悄話一樣嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>안녕하십니까, 여러분!</color>","JPN":"<color=#ffd34c>ごきげんよう、皆様！</color>","ENG":"<color=#ffd34c>Good day, everyone!</color>","TWN":"<color=#ffd34c>哈囉～你們好！</color>"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_CROWD"},{"id":"L32_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>오늘도 즐거운 하루 보내고 계신가요?</color>","JPN":"<color=#ffd34c>今日も楽しい時間を過ごしていますか？</color>","ENG":"<color=#ffd34c>How's your day going so far?</color>","TWN":"<color=#ffd34c>今天也過得開心嗎？</color>"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"우왓! 진짜로 말을 하잖아?","JPN":"わっ！　本当に喋った！","ENG":"Wah! It really talks!","TWN":"哇賽！電視真的會說話欸！"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"바보야. 이건 그냥 쇼호스트 목소리잖아. 방송 소리라고.","JPN":"バカ言わないで。ただのテレビの司会者の声でしょ。音声放送に決まってるわ。","ENG":"You fool, that's the show host talking. On a program.","TWN":"你傻啦？很明顯是主持人的聲音好嗎？是節目啦！"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>그냥 방송이 아닙니다, 제시카! 청중과의 인터랙션이 가미된 특별 라이브 쇼라고요!</color>","JPN":"<color=#ffd34c>普通の放送ではありませんよ、ジェシカ！　視聴者とのインタラクションが加味されたスペシャルライブショーなのですから！</color>","ENG":"<color=#ffd34c>Not just any program, Jessica! This is a special live show, with real-time interaction with the audience!</color>","TWN":"<color=#ffd34c>這可不是一般的節目喔，潔西卡！這可是和觀眾互動的特別直播節目！</color>"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"응? 방금 내 이름이 들린 거 같은데… 우연인가?","JPN":"ん？　今私の名前が聞こえた気がする……偶然？","ENG":"Hm? I think I just heard my name... Was it just a coincidence?","TWN":"嗯？它剛是說我的名字嗎？…還是我聽錯？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>우연일 수도, 아닐 수도 있죠! 그건 받아들이는 입장의 차이일 뿐이니까요.</color>","JPN":"<color=#ffd34c>偶然かもしれないし、そうじゃないかもしれません！　それは受け取り方次第なのですから。</color>","ENG":"<color=#ffd34c>Maybe. Maybe not. It depends on how you perceive it.</color>","TWN":"<color=#ffd34c>可能是你聽錯，也可能你沒聽錯！兩者的差別在於你接不接受而已。</color>"},"stage":{"bg":"RELIC_OPERATION_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>그리고 아주 우연히! 이곳에선 아주 재미있는 일이 벌어질 겁니다.</color>","JPN":"<color=#ffd34c>そして偶然にも！　ここではとても面白いことが起こるでしょう。</color>","ENG":"<color=#ffd34c>And very coincidentally, something very interesting is about to happen.</color>","TWN":"<color=#ffd34c>而且就這麼剛好！這裡將會發生非常有趣的事喔！</color>"},"stage":{"bg":"RELIC_OPERATION_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>타이틀은 멸망을 향해 걸어 나가는 로봇 대행진!</color>","JPN":"<color=#ffd34c>タイトル名は、滅亡に向けて歩むロボット大行進！</color>","ENG":"<color=#ffd34c>It's called... the \\"March of Robots toward Destruction!\\"</color>","TWN":"<color=#ffd34c>主題是，地獄無門你偏闖之機械人對抗戰！</color>"},"stage":{"bg":"RELIC_OPERATION_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"멸망… 로봇…? 뭔가 재밌게 들리긴 하는데?","JPN":"滅亡……ロボット……？　なんだか面白そうに聞こえるな。","ENG":"Robots? Destruction? That does sound interesting, doesn't it?","TWN":"地獄…機械人…？聽起來好像有點意思？"},"stage":{"bg":"RELIC_OPERATION_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>거기 당신! 유령을 믿으시나요?</color>","JPN":"<color=#ffd34c>そこのあなた！　幽霊を信じますか？</color>","ENG":"<color=#ffd34c>Hey, you! Do you believe in ghosts?</color>","TWN":"<color=#ffd34c>我說你！你相信有幽靈嗎？</color>"},"stage":{"bg":"RELIC_OPERATION_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L46_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"응? 사람이 죽으면 되는 그 유령 말이야?","JPN":"え？　死んだ人が化けてでてくる幽霊のことか？","ENG":"Huh? You mean what people become when they die?","TWN":"鬼？你是說人死後會變成的那個幽靈嗎？"},"stage":{"bg":"RELIC_OPERATION_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>아아, 이런 천편일률적인 사고방식이라니. 안타깝지만 반은 오답이군요.</color>","JPN":"<color=#ffd34c>あーあ、そんな面白味のない考えをお持ちだなんて。残念ながら半分しか正解していません。</color>","ENG":"<color=#ffd34c>Ah, such a rigid way of thinking! Sorry, but that's only half-correct.</color>","TWN":"<color=#ffd34c>哎呀～真是頭腦簡單四肢發達，很可惜，你只答對一半！</color>"},"stage":{"bg":"RELIC_OPERATION_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM_02"},{"id":"L48_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c> 사람이 아닌 것도 얼마든지 유령이 될 수 있습니다. 시간에 얽매여 있는 존재라면 누구나 가능하죠!</color>","JPN":"<color=#ffd34c> 人ではないものも幽霊になります。時間に縛られている存在なら、どんなものでも幽霊になることができます！</color>","ENG":"<color=#ffd34c> Even things that are not people can become ghosts so long as they're bound by time</color>","TWN":"<color=#ffd34c>在不是人的狀態下也可能變成幽靈，被困在時間裡的話，誰都可能變成幽靈！</color>"},"stage":{"bg":"RELIC_OPERATION_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>그리고 그걸 증명하는 과정이, 지금 이 순간 펼쳐지게 될 겁니다!</color>","JPN":"<color=#ffd34c>そしてその証明が、今この瞬間から繰り広げられるのです！</color>","ENG":"<color=#ffd34c>and proof of this theory will unfold right before your eyes, right here and now!</color>","TWN":"<color=#ffd34c>現在！就要來證明這件事！</color>"},"stage":{"bg":"RELIC_OPERATION_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD"},{"id":"L2_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"이게 무슨 소리지?!","JPN":"なんの音！？","ENG":"What's that noise?","TWN":"這是什麼聲音？！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_MECHANIC_BAYREN_SKILL_LOOP"},{"id":"L3_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"공장 쪽에서 나는 소리 같은데?","JPN":"工場の方から聞こえてきたぞ？","ENG":"It's coming from the factory.","TWN":"好像是從工廠那邊發出來的？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"설마 공장이 다시 작동하는 건가?!","JPN":"まさか工場が稼働し始めたのか！？","ENG":"The factory can't be operating again, can it?","TWN":"是工廠在運作嗎？！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"…분노가 느껴져.","JPN":"……怒りを感じる。","ENG":"...I can feel anger.","TWN":"…感覺到憤怒。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"그런데, 그 안은 텅 비어 있어.","JPN":"でも、その中は空っぽなの。","ENG":"But the factory is empty on the inside.","TWN":"可是，那裡面明明是空的。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"이봐, 호스트! 이거 당신이 벌이고 있는 짓이야?!","JPN":"ちょっと、司会者！　これはあんたの仕業なの？","ENG":"Hey, host guy. Is it you who's doing this?","TWN":"喂，主持人！是你搞的鬼嗎？！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>하하, 그럴 리가요. 전 단순한 길잡이, TV 속 호스트일 뿐인 걸요.</color>","JPN":"<color=#ffd34c>はははっ、まさか。私はただの案内人、テレビの中の司会者にすぎません。</color>","ENG":"<color=#ffd34c>Hah hah. Of course not. I'm just a TV host, a simple guide.</color>","TWN":"<color=#ffd34c>哈哈～怎麼可能～我不過就是個電視裡的主持人～</color>"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_LAUGH"},{"id":"L10_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>이건 그저 고장 난 시계의 시간이 우연히 딱 맞아떨어진 상황일 뿐이랍니다.</color>","JPN":"<color=#ffd34c>これはただ、故障した時計の針が偶然ぴったり合ってしまっただけの状況にすぎません。</color>","ENG":"<color=#ffd34c>You just happened to be here when the factory's broken clock started ticking again.</color>","TWN":"<color=#ffd34c>這只是壞掉的時鐘時間剛好吻合而已。</color>"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>이곳은 운명을 잃은 기계들의 무덤. 수많은 전쟁과 저항이 있었던 기계의 터전.</color>","JPN":"<color=#ffd34c>ここは運命を失った機械たちの墓場。幾多の戦争と抵抗があった機械の住処。</color>","ENG":"<color=#ffd34c>This place is actually a graveyard of purposeless machines, left abandoned after fighting countless wars and disputes.</color>","TWN":"<color=#ffd34c>這個地方是失去生命的機械墳墓，它們曾經抗爭過，但還是遭到遺棄。</color>"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>생산과 파괴라는 무한한 순환에 갇혀 있던 중에, 돌연 유령이란 형태로 현실에 도래한 것이죠.</color>","JPN":"<color=#ffd34c>生産と破壊という無限の循環に閉じ込められていた中、突然幽霊という形で現実に顕現したのです。</color>","ENG":"<color=#ffd34c>They suddenly broke out of their endless cycle of production and destruction, materializing in reality as ghosts.</color>","TWN":"<color=#ffd34c>原本受困於生產和破壞的無限循環中，現在突變成幽靈來到現世。</color>"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"대체 무슨 소리야! 하나도 못 알아 먹겠잖아!","JPN":"いったい何を言ってるの？　全く理解できないんだけど？","ENG":"What the hell are you talking about? You're making no sense!","TWN":"你到底在說什麼鬼話？完全聽不懂！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>이런, 미안합니다. 제가 요즘 세상 사람들 언어는 아직 배워나가는 중이라서요.</color>","JPN":"<color=#ffd34c>おっと、すみません。この時代の言葉はまだ勉強中でして。</color>","ENG":"<color=#ffd34c>Oops, my apologies. I'm still in the process of learning a modern language.</color>","TWN":"<color=#ffd34c>哎呀～很抱歉，因為我還在學習人類的語言中。</color>"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>그림자 전당이라는 이름을 들어보셨다면, 그것과 꽤 유사하다고 말씀드리고 싶군요.</color>","JPN":"<color=#ffd34c>影の殿堂という名前を聞いたことがあるのなら、それと似たものと申し上げましょう。</color>","ENG":"<color=#ffd34c>If you have heard of the Shadow Palaces, this place is similar to them.</color>","TWN":"<color=#ffd34c>你有聽過暗影殿堂嗎？跟那個很類似。</color>"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"그림자 전당? 갑자기 그런 엄청난 이름이 왜 여기서 튀어나오는데?!","JPN":"影の殿堂？　なぜ急にそんな名前が出てくるんだ？","ENG":"The Shadow Palaces? Why do you mention that all of a sudden?","TWN":"暗影殿堂？為什麼突然提到它？！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"와아악! 뭐야?","JPN":"わっ！　なんだ！？","ENG":"Wah! What's that?","TWN":"哎唷喂呀！什麼啦？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"저건… 전차잖아? 공장에서 튀어나온 건가?","JPN":"あれは……戦車じゃないか？　工場から出てきたってのか？","ENG":"It's... a TANK? Did it come out of the factory?","TWN":"那個…不是戰車嗎？從工廠裡蹦出來的嗎？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"침식체의 기운… 안 느껴져.","JPN":"侵食体の気配……感じられない。","ENG":"C.O... I don't feel their energy from it.","TWN":"沒感受到…侵蝕體的存在。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"하지만 찰리를 공격했어. 부술 거야.","JPN":"でもチャーリーを攻撃した。壊してやる。","ENG":"But it attacked Charlie. I'm going to destroy it.","TWN":"可是它攻擊查理，必須死。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"어이, 오르카!","JPN":"おい、オルカ！","ENG":"Hey, Orca!","TWN":"喂，奧爾卡!"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"…공장에서 정말로 탱크가 튀어나오다니. 시답잖은 농담은 아닌 것 같네.","JPN":"……工場から本当に戦車が出てくるなんて、ただの冗談ではなさそうね。","ENG":"I can't believe a tank came out of the factory. It's not a joke.","TWN":"…竟然真的從工廠裡蹦出坦克來？看來它沒在開玩笑。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"그림자도 때려부수면 처치할 수 있다던데, 그럼 우리가 저 공장을 부수면 되는 건가?","JPN":"シャドウも打ち砕けば倒せると聞いたけど……ってことは、私たちがあの工場を破壊すればいいってこと？","ENG":"Even shadows can be destroyed. So can that factory, right?","TWN":"就算是暗影，也是可以被毀掉的，所以現在只需要毀掉那個工廠就好吧？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>부술 수 없는 것을 부수겠다는 것만큼 허황된 이야기가 또 있을까요?</color>","JPN":"<color=#ffd34c>壊せないものを壊すなんて、こんな馬鹿げた話が他にあるでしょうか？</color>","ENG":"<color=#ffd34c>You want to destroy the indestructible. I don't think I've ever heard anything more absurd than that.</color>","TWN":"<color=#ffd34c>竟然說要毀掉無法被毀掉的東西，有比這更誇張的事嗎？</color>"},"stage":{"bg":"RELIC_OPERATION_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L32_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>하지만, 여러분은 인간입니다. 어떤 비참한 현실 앞에서도 적응할 줄 아는 놀라운 존재라고요.</color>","JPN":"<color=#ffd34c>ですが、皆様は人間です。どんな悲惨な現実を目の前にしても適応できる驚くべき存在です。</color>","ENG":"<color=#ffd34c>But you're humans, amazing creatures that can adapt to any situation, no matter how desperate.</color>","TWN":"<color=#ffd34c>不過你們是人類，有著無論遇到什麼樣悲慘的事，也能夠適應進化的驚人能力。</color>"},"stage":{"bg":"RELIC_OPERATION_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>종말의 잔재인 침식체들을 쳐부수고 그들의 이터니움을 자원으로 이용하는 것처럼 말이죠!</color>","JPN":"<color=#ffd34c>終末の残滓である侵食体を打ち破り、彼らのエタニウムを資源として利用することとまったく同じです！</color>","ENG":"<color=#ffd34c>You've even learned how to hunt the C.O., the remnants of destroyed worlds, and make use of their eternium.</color>","TWN":"<color=#ffd34c>就像你們打倒殘留的侵蝕體後，將它們的永恆之金據為己用一樣！</color>"},"stage":{"bg":"RELIC_OPERATION_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>적을 완전히 없앨 수 없다면, 차라리 그 적을 때려부수고 잔해를 잔뜩 수집해서 자원으로 이용하자고요.</color>","JPN":"<color=#ffd34c>敵を完全に消し去ることができないのなら、敵を叩き潰して残骸を資源として利用しましょう。</color>","ENG":"<color=#ffd34c>If you can't destroy these enemies completely, then why not break them apart and use their parts for various purposes instead?</color>","TWN":"<color=#ffd34c>若無法將敵人完全消滅，還不如就將敵人擊潰後，收集大量殘骸作為資源使用！</color>"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L39_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>제 의견이 어떻습니까?</color>","JPN":"<color=#ffd34c>いかがでしょう？</color>","ENG":"<color=#ffd34c>Don't you agree?</color>","TWN":"<color=#ffd34c>覺得我的提議如何？</color>"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"찰리, 본부에 연락해서 사람들을 불러모아.","JPN":"チャーリー、本部に連絡して人を集めてきて。","ENG":"Charlie, call HQ for reinforcements.","TWN":"查理，通知總部召集大家！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"뭐? 진심이야? 회사까지 동원해서 저 공장을 공격한다고?","JPN":"え？　本気か？　会社まで動員してあの工場を攻撃するのか？","ENG":"What? Are you serious? You want to make a full-fledged attack on the factory?","TWN":"什麼？你認真的嗎？你要動員整間公司攻擊那個工廠？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"내버려두면 공장은 계속 작동하면서 기계를 만들어낼 거야. 그럼 내 고향뿐만 아니라 일대 전부를 위협하게 되겠지.","JPN":"放っておけばあの工場は機械を作り続けるはずよ。そうなると私の地元だけではなく、この一帯全域が危険に晒されるわ。","ENG":"If left alone, it'll continue to produce machines. It's a threat, not just to my hometown, but everywhere else in the area.","TWN":"不管它的話，它會持續運作製造出更多機械。這樣的話，不只是我的故鄉、甚至連這一帶全部都會陷入危險！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"그러니 잔말 말고 서둘러!","JPN":"だからさっさと連絡を入れて！","ENG":"So, shut up and get on with it!","TWN":"所以廢話少說！動作快！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"아, 알았어!","JPN":"わ、わかったよ！","ENG":"Oh, okay!","TWN":"喔，好！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>하하, 멋지군요. 좋은 쇼 인트로가 되겠어요.</color>","JPN":"<color=#ffd34c>ハハハ、素晴らしいです。最高の幕開けになりそうですね。</color>","ENG":"<color=#ffd34c>Hah hah. Nice! Now, I've got a good opening scene.</color>","TWN":"<color=#ffd34c>哈哈～帥喔～你很懂節目要的效果呢！</color>"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L49_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"당신이 저 사태의 원흉이 아니라면, 대체 당신은 정체가 뭐지? 본체는 어디에 있는 거야?","JPN":"あんたがこの事態の元凶でなければ、いったい何者なの？　本体はどこにいるの？","ENG":"If you're not behind this catastrophe, what are you doing here? And where the hell are you, really?","TWN":"你不是幕後主使者的話，那你到底是誰，真正的你藏在哪裡？！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>실망시켜 미안하지만 지금은 이게 제 본체에요, 제시카.</color>","JPN":"<color=#ffd34c>ガッカリさせて申し訳ございませんが、今はこれが私の本体ですよ、ジェシカ。</color>","ENG":"<color=#ffd34c>I'm sorry to disappoint you, but for now, I'm in this TV, Jessica.</color>","TWN":"<color=#ffd34c>很抱歉，潔西卡，讓你失望了，這個就是真正的我。</color>"},"stage":{"bg":"RELIC_OPERATION_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>저는 마르퀴즈. 상자 속 작은 길잡이랍니다.</color>","JPN":"<color=#ffd34c>私はマーキス。箱の中の小さな案内人です。</color>","ENG":"<color=#ffd34c>My name is Marquis. I'm your little guide in the box.</color>","TWN":"<color=#ffd34c>我叫馬奎茲，是電視裡的旁白。</color>"},"stage":{"bg":"RELIC_OPERATION_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>세계 곳곳에서 일어나는 작은 구경거리들을 찾고 있는 관중이자, 방관자이자, 해설자이기도 하죠.</color>","JPN":"<color=#ffd34c>世界各地で繰り広げられる様々な見せ場を求める観客であり、傍観者であり、解説者でもあります。</color>","ENG":"<color=#ffd34c>I'm also a viewer, observer, and commentator looking for the small spectacles that occur all over the world.</color>","TWN":"<color=#ffd34c>是尋找世界各地奇聞趣事的觀眾，也是旁觀者，也是解說者。</color>"},"stage":{"bg":"RELIC_OPERATION_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};